## API Integration

### api.ts
```typescript
import axios from 'axios';

const API_BASE = import.meta.env.VITE_API_URL || 'http://localhost:8000';

export interface SearchRequest {
  query: string;
  limit?: number;
  salary_min?: number;
  salary_max?: number;
  employment_type?: string;
  alpha?: number;
  expand_query?: boolean;
}

export interface SearchResponse {
  results: JobResult[];
  total_candidates: number;
  search_time_ms: number;
  query_expansion?: string[];
  degraded: boolean;
  cache_hit: boolean;
}

export const api = {
  search: async (request: SearchRequest): Promise<SearchResponse> => {
    const response = await axios.post(`${API_BASE}/api/search`, request);
    return response.data;
  },

  findSimilar: async (jobUuid: string, limit = 10): Promise<SearchResponse> => {
    const response = await axios.post(`${API_BASE}/api/similar`, {
      job_uuid: jobUuid,
      limit,
      exclude_same_company: false
    });
    return response.data;
  },

  searchSkills: async (skill: string, limit = 20): Promise<SearchResponse> => {
    const response = await axios.post(`${API_BASE}/api/search/skills`, {
      skill,
      limit
    });
    return response.data;
  },

  findSimilarCompanies: async (companyName: string, limit = 10) => {
    const response = await axios.post(`${API_BASE}/api/companies/similar`, {
      company_name: companyName,
      limit
    });
    return response.data;
  },

  getHealth: async () => {
    const response = await axios.get(`${API_BASE}/health`);
    return response.data;
  }
};
```

### React Query Hooks
```typescript
// hooks/useSearch.ts
import { useQuery, useMutation } from '@tanstack/react-query';
import { api, SearchRequest } from '../services/api';

export function useSearch() {
  const mutation = useMutation({
    mutationFn: (request: SearchRequest) => api.search(request),
  });

  return {
    search: mutation.mutate,
    data: mutation.data,
    isLoading: mutation.isPending,
    error: mutation.error
  };
}

// hooks/useSimilarJobs.ts
export function useSimilarJobs(jobUuid: string | null) {
  return useQuery({
    queryKey: ['similar', jobUuid],
    queryFn: () => api.findSimilar(jobUuid!),
    enabled: !!jobUuid
  });
}
```

## UI/UX Considerations

### Responsive Design
- Desktop: Side-by-side filter panel and results
- Tablet: Collapsible filter panel
- Mobile: Stacked layout, full-width cards

### Loading States
- Skeleton loaders for job cards while loading
- Search button disabled during search
- "Searching..." text feedback

### Error Handling
- Toast notifications for API errors
- Retry button for failed requests
- Graceful degradation banner when API is degraded

### Performance
- Debounce filter changes (300ms)
- Virtual scrolling for large result sets
- Memoize expensive computations

