### 8. Create API Service
**src/services/api.ts:**
```typescript
import axios from 'axios';
import type { SearchResponse, CompanySimilarity, HealthResponse, Filters } from '../types';

const API_BASE = import.meta.env.VITE_API_URL || '';

const client = axios.create({
  baseURL: API_BASE,
  timeout: 10000,
});

export interface SearchRequest {
  query: string;
  limit?: number;
  salary_min?: number;
  salary_max?: number;
  employment_type?: string;
  region?: string;
  company?: string;
  alpha?: number;
  expand_query?: boolean;
}

export const api = {
  search: async (request: SearchRequest): Promise<SearchResponse> => {
    const response = await client.post('/api/search', request);
    return response.data;
  },

  findSimilar: async (jobUuid: string, limit = 10, excludeSameCompany = false): Promise<SearchResponse> => {
    const response = await client.post('/api/similar', {
      job_uuid: jobUuid,
      limit,
      exclude_same_company: excludeSameCompany,
    });
    return response.data;
  },

  searchSkills: async (skill: string, limit = 20, filters?: Filters): Promise<SearchResponse> => {
    const response = await client.post('/api/search/skills', {
      skill,
      limit,
      ...filters,
    });
    return response.data;
  },

  findSimilarCompanies: async (companyName: string, limit = 10): Promise<CompanySimilarity[]> => {
    const response = await client.post('/api/companies/similar', {
      company_name: companyName,
      limit,
    });
    return response.data;
  },

  getHealth: async (): Promise<HealthResponse> => {
    const response = await client.get('/health');
    return response.data;
  },
};

export default api;
```

### 9. Set Up React Query Provider
**src/main.tsx:**
```typescript
import React from 'react';
import ReactDOM from 'react-dom/client';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import App from './App';
import './index.css';

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      refetchOnWindowFocus: false,
      retry: 1,
    },
  },
});

ReactDOM.createRoot(document.getElementById('root')!).render(
  <React.StrictMode>
    <QueryClientProvider client={queryClient}>
      <App />
    </QueryClientProvider>
  </React.StrictMode>
);
```

