# Task: Build Core UI Components

## What
Create all UI components for the search interface including:
- SearchBar, FilterPanel, JobCard, JobList (core)
- SimilarJobsModal (recommendations)
- SkillCloud (skill visualization)
- CompanySearch (company similarity)
- SearchStats (analytics display)
- DegradedBanner (error state)

## Components to Create

### 1. SearchBar.tsx
```tsx
import { useState, KeyboardEvent } from 'react';
import { MagnifyingGlassIcon, XMarkIcon } from '@heroicons/react/24/outline';

interface SearchBarProps {
  value: string;
  onChange: (value: string) => void;
  onSearch: () => void;
  isLoading?: boolean;
  placeholder?: string;
}

export function SearchBar({ value, onChange, onSearch, isLoading, placeholder }: SearchBarProps) {
  const handleKeyDown = (e: KeyboardEvent) => {
    if (e.key === 'Enter' && !isLoading) {
      onSearch();
    }
  };

  return (
    <div className="relative flex items-center">
      <MagnifyingGlassIcon className="absolute left-3 h-5 w-5 text-gray-400" />
      <input
        type="text"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onKeyDown={handleKeyDown}
        placeholder={placeholder || "Search jobs semantically..."}
        className="w-full pl-10 pr-10 py-3 border border-gray-300 rounded-lg 
                   focus:ring-2 focus:ring-blue-500 focus:border-transparent"
        disabled={isLoading}
      />
      {value && (
        <button onClick={() => onChange('')} className="absolute right-14 text-gray-400">
          <XMarkIcon className="h-5 w-5" />
        </button>
      )}
      <button
        onClick={onSearch}
        disabled={isLoading || !value.trim()}
        className="ml-2 px-6 py-3 bg-blue-600 text-white rounded-lg 
                   hover:bg-blue-700 disabled:bg-gray-300 transition-colors"
      >
        {isLoading ? 'Searching...' : 'Search'}
      </button>
    </div>
  );
}
```

### 2. FilterPanel.tsx
