            placeholder="e.g., 5000"
            className="w-full px-3 py-2 border rounded-md text-sm"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-600 mb-1">Max Salary</label>
          <input
            type="number"
            value={filters.salaryMax || ''}
