      </div>

      {/* Company */}
      <div>
        <label className="block text-sm font-medium text-gray-600 mb-1">Company</label>
        <input
          type="text"
          value={filters.company || ''}
          onChange={(e) => updateFilter('company', e.target.value || undefined)}
