### 3. JobCard.tsx
```tsx
interface JobCardProps {
  job: JobResult;
  onFindSimilar: (uuid: string) => void;
}

export function JobCard({ job, onFindSimilar }: JobCardProps) {
  const formatSalary = () => {
    if (job.salary_min && job.salary_max) {
      return `$${job.salary_min.toLocaleString()} - $${job.salary_max.toLocaleString()}`;
    } else if (job.salary_min) {
      return `$${job.salary_min.toLocaleString()}+`;
    }
    return 'Salary not specified';
  };

  const skills = job.skills?.split(',').slice(0, 5) || [];
  const similarityPercent = Math.round(job.similarity_score * 100);

  return (
    <div className="bg-white p-4 rounded-lg shadow-sm border hover:shadow-md transition-shadow">
      <div className="flex justify-between items-start mb-2">
        <div className="flex-1">
          <a href={job.job_url} target="_blank" rel="noopener noreferrer"
             className="text-lg font-semibold text-blue-600 hover:underline">
            {job.title}
          </a>
          <p className="text-gray-600">{job.company_name || 'Unknown Company'}</p>
        </div>

        {/* Similarity Score Badge */}
        <div className="flex items-center space-x-1 bg-green-100 text-green-800 px-2 py-1 rounded-full text-sm">
          <SparklesIcon className="h-4 w-4" />
          <span>{similarityPercent}% match</span>
        </div>
      </div>

      <div className="text-sm text-gray-500 mb-3 space-y-1">
        <p>{formatSalary()}</p>
        {job.location && <p>{job.location}</p>}
      </div>

      {/* Skills */}
      {skills.length > 0 && (
        <div className="flex flex-wrap gap-1 mb-3">
          {skills.map((skill, i) => (
            <span key={i} className="bg-gray-100 text-gray-700 px-2 py-0.5 rounded text-xs">
              {skill.trim()}
            </span>
          ))}
        </div>
      )}

      <p className="text-sm text-gray-600 line-clamp-2 mb-3">{job.description}</p>

      <div className="flex justify-end">
        <button
          onClick={() => onFindSimilar(job.uuid)}
          className="text-sm text-blue-600 hover:text-blue-800 flex items-center space-x-1"
        >
          <SparklesIcon className="h-4 w-4" />
          <span>Find Similar</span>
        </button>
      </div>
    </div>
  );
}
```

