### 5. SkillCloud.tsx (NEW)
```tsx
interface SkillCloudItem {
  skill: string;
  job_count: number;
  cluster_id?: number;
}

interface SkillCloudProps {
  skills: SkillCloudItem[];
  onSkillClick: (skill: string) => void;
  isLoading: boolean;
}

// Color palette for clusters
const CLUSTER_COLORS = [
  'bg-blue-100 text-blue-800',
  'bg-green-100 text-green-800',
  'bg-purple-100 text-purple-800',
  'bg-orange-100 text-orange-800',
  'bg-pink-100 text-pink-800',
  'bg-teal-100 text-teal-800',
];

export function SkillCloud({ skills, onSkillClick, isLoading }: SkillCloudProps) {
  if (isLoading) {
    return <div className="animate-pulse h-32 bg-gray-100 rounded-lg" />;
  }

  // Calculate font sizes based on frequency
  const maxCount = Math.max(...skills.map(s => s.job_count));
  const minCount = Math.min(...skills.map(s => s.job_count));

  const getFontSize = (count: number) => {
    const normalized = (count - minCount) / (maxCount - minCount || 1);
    return 0.75 + normalized * 1; // 0.75rem to 1.75rem
  };

  const getColor = (clusterId?: number) => {
    if (clusterId === undefined) return 'bg-gray-100 text-gray-700';
    return CLUSTER_COLORS[clusterId % CLUSTER_COLORS.length];
  };

  return (
    <div className="bg-white p-4 rounded-lg shadow-sm border">
      <h3 className="font-semibold text-gray-700 mb-3">Popular Skills</h3>
      <div className="flex flex-wrap gap-2">
        {skills.map((skill) => (
          <button
            key={skill.skill}
            onClick={() => onSkillClick(skill.skill)}
            style={{ fontSize: `${getFontSize(skill.job_count)}rem` }}
            className={`px-2 py-1 rounded-full hover:opacity-80 transition-opacity ${getColor(skill.cluster_id)}`}
            title={`${skill.job_count} jobs`}
          >
            {skill.skill}
          </button>
        ))}
      </div>
    </div>
  );
}
```

