interface CompanySimilarity {
  company_name: string;
  similarity_score: number;
  job_count: number;
  avg_salary?: number;
  top_skills: string[];
}

interface CompanySearchProps {
  onSearch: (companyName: string) => void;
  results: CompanySimilarity[];
  isLoading: boolean;
}

export function CompanySearch({ onSearch, results, isLoading }: CompanySearchProps) {
  const [companyName, setCompanyName] = useState('');

  const handleSearch = () => {
    if (companyName.trim()) {
      onSearch(companyName.trim());
    }
  };

  return (
    <div className="bg-white p-4 rounded-lg shadow-sm border">
      <h3 className="font-semibold text-gray-700 mb-3">Find Similar Companies</h3>

      <div className="flex gap-2 mb-4">
        <input
          type="text"
          value={companyName}
          onChange={(e) => setCompanyName(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
          placeholder="Enter company name..."
          className="flex-1 px-3 py-2 border rounded-md text-sm"
        />
        <button
          onClick={handleSearch}
          disabled={isLoading || !companyName.trim()}
          className="px-4 py-2 bg-blue-600 text-white rounded-md text-sm disabled:bg-gray-300"
        >
          {isLoading ? '...' : 'Find'}
        </button>
      </div>

      {results.length > 0 && (
        <div className="space-y-2">
          {results.map((company) => (
            <div key={company.company_name} className="p-3 border rounded-lg">
              <div className="flex justify-between items-start">
                <div>
                  <p className="font-medium">{company.company_name}</p>
                  <p className="text-sm text-gray-500">
                    {company.job_count} jobs
                    {company.avg_salary && ` · Avg $${company.avg_salary.toLocaleString()}`}
                  </p>
                </div>
                <span className="text-sm text-green-600">
                  {Math.round(company.similarity_score * 100)}% similar
                </span>
              </div>
              {company.top_skills.length > 0 && (
                <div className="mt-2 flex flex-wrap gap-1">
                  {company.top_skills.slice(0, 5).map((skill) => (
                    <span key={skill} className="bg-gray-100 text-xs px-1.5 py-0.5 rounded">
                      {skill}
                    </span>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
