## Main App Integration

```tsx
// App.tsx
function App() {
  const [query, setQuery] = useState('');
  const [filters, setFilters] = useState<Filters>({});
  const [results, setResults] = useState<SearchResponse | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [similarModal, setSimilarModal] = useState<{open: boolean, job: JobResult | null}>({open: false, job: null});
  const [similarJobs, setSimilarJobs] = useState<JobResult[]>([]);
  const [skillCloud, setSkillCloud] = useState<SkillCloudItem[]>([]);

  useEffect(() => {
    // Load skill cloud on mount
    fetch('/api/skills/cloud?limit=50')
      .then(res => res.json())
      .then(setSkillCloud);
  }, []);

  const handleSearch = async () => {
    setIsLoading(true);
    const res = await fetch('/api/search', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ query, ...filters })
    });
    setResults(await res.json());
    setIsLoading(false);
  };

  const handleFindSimilar = async (uuid: string) => {
    const job = results?.results.find(j => j.uuid === uuid);
    setSimilarModal({open: true, job: job || null});

    const res = await fetch('/api/similar', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ job_uuid: uuid, limit: 10 })
    });
    const data = await res.json();
    setSimilarJobs(data.results);
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-6xl mx-auto p-4">
        <h1 className="text-2xl font-bold mb-6">MCF Job Search</h1>

        <DegradedBanner show={results?.degraded || false} />

        <SearchBar value={query} onChange={setQuery} onSearch={handleSearch} isLoading={isLoading} />

        <div className="mt-4 grid grid-cols-4 gap-4">
          <div className="col-span-1 space-y-4">
            <FilterPanel filters={filters} onChange={setFilters} onClear={() => setFilters({})} />
            <SkillCloud skills={skillCloud} onSkillClick={(s) => {setQuery(s); handleSearch();}} isLoading={false} />
          </div>

          <div className="col-span-3">
            {results && <SearchStats {...results} />}
            <JobList jobs={results?.results || []} isLoading={isLoading} onFindSimilar={handleFindSimilar} />
          </div>
        </div>

        <SimilarJobsModal
          isOpen={similarModal.open}
          onClose={() => setSimilarModal({open: false, job: null})}
          sourceJob={similarModal.job}
          similarJobs={similarJobs}
          isLoading={false}
        />
      </div>
    </div>
  );
}
